import json, os, re
j=json.load(open('/private/tmp/get_refs.json'))
for f, arr in j['byFile'].items():
    if not os.path.exists(f): continue
    lines=open(f).read().splitlines()
    for r in arr:
        l=r['line']; s=lines[l-1] if l-1 < len(lines) else ''
        if '.get(' in s and not re.search(r\"\\.get\\(\\s*['\\\"]\", s):
            if re.search(r'JsonNode|node|get\\([0-9]|get\\(index|get\\(i\\)|get\\(ix\\)|get\\(qix\\)|_delegate', s):
                print(f\"{f}:{l}: in {r['in']}: {s.strip()}\")
PY"

