/bin/zsh -lc "python3 - <<'PY'
import os,re
for root,_,files in os.walk('src'):
  for fn in files:
    if not fn.endswith('.java'): continue
    f=os.path.join(root,fn)
    txt=open(f).read()
    if not re.search(r'\\b(JsonNode|ArrayNode|ObjectNode|ContainerNode|ValueNode)\\b', txt): continue
    lines=txt.splitlines()
    for i,s in enumerate(lines,1):
      if '.get(' in s and re.search(r'\\.get\\(\\s*(-?\\d+|[a-zA-Z_][a-zA-Z0-9_]*)\\s*\\)', s):
        print(f'{f}:{i}:{s.strip()}')
PY"

