// [databind#3002]
@Test
public void testCustomDeserializerWithReadTreeAsValue() throws Exception
{
    final String json = a2q("{'point':{'x':13, 'y':-4}, 'name':'Foozibald' }");
    NamedPoint result = MAPPER.readValue(json, NamedPoint.class);
    assertNotNull(result);
    assertEquals("Foozibald", result.name);
    assertEquals(new Point(13, -4), result.point);

    // and with JavaType variant too

    r1 = mapper.treeToValue(root, mapper.constructType(Root.class));
    assertEquals(13, r1.leaf.value);

    // ... also TypeReference
    r1 = mapper.treeToValue(root, new TypeReference<Root>() {});
    assertEquals(13, r1.leaf.value);

    JSON = "[{\"leaf\":{\"value\":13}}, {\"leaf\":{\"value\":12}}]";
    root = mapper.readTree(JSON);
    List<Root> array = mapper.treeToValue(root, new TypeReference<List<Root>>() {});
    assertEquals(2, array.size());
    assertEquals(13, array.get(0).leaf.value);
    assertEquals(12, array.get(1).leaf.value);
}

